const body = $json.body ?? $json;
const contact = body.contact ?? {};
const question = (body.question || body.sourceQuestion || body.specificQuestion || '').trim();
const draftRequest = (body.draftRequest || body.projectSummary || body.residentSummary || '').trim();
if (!question && !draftRequest) throw new Error('question or draftRequest is required');
if (!contact.email && !contact.phone && !body.email && !body.phone) {
  throw new Error('At least one contact method is required');
}
const binary = $binary ?? {};
const attachmentBinary = Object.entries(binary).map(([key, item]) => ({
  key,
  fileName: item.fileName || key,
  mimeType: item.mimeType || null,
  fileSize: typeof item.fileSize === 'number' ? item.fileSize : null,
}));
const attachments = [
  ...attachmentBinary,
  ...((Array.isArray(body.attachments) ? body.attachments : [])
    .map((item) => {
      if (typeof item === 'string') return { fileName: item };
      if (item && typeof item === 'object') return item;
      return null;
    })
    .filter(Boolean)),
  ...((Array.isArray(body.images) ? body.images : [])
    .map((item) => {
      if (typeof item === 'string') return { fileName: item };
      if (item && typeof item === 'object') return item;
      return null;
    })
    .filter(Boolean))
];
const citations = Array.isArray(body.sourceCitations) ? body.sourceCitations : Array.isArray(body.citations) ? body.citations : [];
const chatTranscript = Array.isArray(body.chatTranscript) ? body.chatTranscript : Array.isArray(body.chat_transcript) ? body.chat_transcript : [];
const record = {
  submitted_at: body.submittedAt || body.submitted_at || new Date().toISOString(),
  slug: body.slug || 'saybrook-zoning',
  jurisdiction: body.jurisdiction || 'Saybrook Township',
  request_type: body.requestType || body.request_type || body.projectType || 'zoning guidance',
  applicant_name: body.fullName || body.applicant_name || contact.name || body.name || '',
  email: body.email || contact.email || '',
  phone: body.phone || contact.phone || '',
  preferred_contact: body.preferredContact || body.preferred_contact || 'email',
  property_address: body.propertyAddress || body.property_address || body.address || '',
  project_type: body.projectType || body.project_type || '',
  project_summary: draftRequest || '',
  specific_question: question || '',
  ai_summary: body.aiSummary || body.aiContextSummary || '',
  source_answer: body.sourceAnswer || body.aiContextSummary || '',
  source_citations_json: JSON.stringify(citations),
  attachments_json: JSON.stringify(attachments),
  chat_transcript_json: JSON.stringify(chatTranscript),
  status: body.status || 'new'
};
return [{ json: record }];

const body = $json.body ?? $json;
const binary = $binary ?? {};
const uploadUrl =
  $env.SAYBROOK_ATTACHMENT_UPLOAD_URL ||
  'https://new-ashtabula-initiative.vercel.app/api/saybrook-blob-upload';

const attachmentEntries = Object.entries(binary).map(([key, item], index) => ({
  key,
  fileName: item.fileName || key || `attachment-${index + 1}`,
  mimeType: item.mimeType || 'application/octet-stream',
  size: typeof item.fileSize === 'number' ? item.fileSize : null,
  data: item.data || item.fileData || '',
}));

if (!attachmentEntries.length) {
  return [{
    json: {
      ...body,
      attachments: Array.isArray(body.attachments) ? body.attachments : [],
      uploadedAttachments: [],
    },
  }];
}

const response = await fetch(uploadUrl, {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    Accept: 'application/json',
  },
  body: JSON.stringify({
    slug: body.slug || 'saybrook-zoning',
    jurisdiction: body.jurisdiction || 'Saybrook Township',
    requestId: body.requestId || body.id || '',
    attachments: attachmentEntries,
  }),
});

if (!response.ok) {
  const detail = await response.text().catch(() => '');
  throw new Error(`Attachment upload failed ${response.status}: ${detail}`);
}

const result = await response.json().catch(() => ({}));
const uploadedAttachments = Array.isArray(result.attachments) ? result.attachments : [];

return [{
  json: {
    ...body,
    attachments: uploadedAttachments,
    uploadedAttachments,
    uploadedAttachmentCount: uploadedAttachments.length,
  },
}];
